    renewal-period="60"
    counter-key="@((string)context.Variables["tenant_id"])"
    increment-condition="@(context.Response.StatusCode == 200)"
    retry-after-header-name="Retry-After"
    retry-after-variable-name="retry_after_seconds"
    remaining-calls-header-name="X-RateLimit-Remaining"
    total-calls-header-name="X-RateLimit-Limit" />







        application/json

      @{
        var retryAfter = context.Variables.GetValueOrDefault("retry_after_seconds") ?? "60";
        var tenantId = context.Variables.GetValueOrDefault("tenant_id") ?? "unknown";
        var tier = context.Variables.GetValueOrDefault("tenant_tier") ?? "standard";
        return new JObject(
          new JProperty("error", "rate_limit_exceeded"),
          new JProperty("tenant_id", tenantId),
          new JProperty("tier", tier),
          new JProperty("retry_after_seconds", int.Parse(retryAfter)),
          new JProperty("message", $"Rate limit exceeded for tenant '{tenantId}' on tier '{tier}'. Retry after {retryAfter}s.")
        ).ToString();
      }
